// Input: city, state, categories (comma-separated), radius
const city = $input.first().json.body.city || 'Fayetteville';
const state = $input.first().json.body.state || 'NC';
const categories = ($input.first().json.body.categories || 'tattoo shop,barbershop,hair salon,gym,restaurant,bar').split(',').map(s => s.trim());
const radius = $input.first().json.body.radius || 10;

// Generate search queries for each category
const queries = categories.map(cat => `${cat} in ${city}, ${state}`);

return queries.map(q => ({ json: { query: q, city, state, categories, radius } }));

// Parse Google Places results into prospect records
const results = $input.all();
const prospects = [];

for (const item of results) {
  const places = item.json.results || [];

  for (const place of places) {
    if (!place.name) continue;

    prospects.push({
      json: {
        business_name: place.name,
        address: place.formatted_address || '',
        phone: place.formatted_phone_number || '',
        website: place.website || '',
        google_rating: place.rating || null,
        review_count: place.user_ratings_total || 0,
        category: place.types ? place.types[0] : 'other',
        google_place_id: place.place_id,
        lat: place.geometry?.location?.lat,
        lng: place.geometry?.location?.lng,
        source: 'google_maps'
      }
    });
  }
}

// Deduplicate by business_name + address
const seen = new Set();
const unique = prospects.filter(p => {
  const key = `${p.json.business_name}|${p.json.address}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

console.log(`Found ${unique.length} unique prospects`);
return unique;
